        //                       string(name: 'NODE_LABEL', value: params.NODE_LABEL)
        //                   ]
        //         }
        //     }
        // }

        stage('Run joba') {
            steps {
                script {
                    build job: 'joba',
                          propagate: false,
                          parameters: [
                              string(name: 'WEBEX_ROOM_ID', value: env.WEBEX_ROOM_ID),
                              string(name: 'NODE_LABEL', value: params.NODE_LABEL)
                          ]
                }
            }
        }
        
        stage('Run config_group_platform_usb_disable') {
            steps {
                script {
                    build job: 'config_group_platform_usb_disable',
                          propagate: false,
                          parameters: [
                              string(name: 'WEBEX_ROOM_ID', value: env.WEBEX_ROOM_ID),
                              string(name: 'NODE_LABEL', value: params.NODE_LABEL)
                          ]
                }
            }
        }
        
        stage('Run jobb') {
            steps {
                script {
                    build job: 'jobb',
                          propagate: false,
                          parameters: [
                              string(name: 'WEBEX_ROOM_ID', value: env.WEBEX_ROOM_ID),
                              string(name: 'NODE_LABEL', value: params.NODE_LABEL)
                          ]
                }
            }
        }
        
        stage('Run config_group_platform_service_timestamp') {
            steps {
                script {
                    build job: 'config_group_platform_service_timestamp',
                          propagate: false,
                          parameters: [
                              string(name: 'WEBEX_ROOM_ID', value: env.WEBEX_ROOM_ID),
                              string(name: 'NODE_LABEL', value: params.NODE_LABEL)
                          ]
                }
            }
